import { behavior as computedBehavior } from 'miniprogram-computed';
import signBehavior from "../../behavior/index";
Page({
    behaviors: [computedBehavior, signBehavior],

  /**
   * 页面的初始数据
   */
  data: {

  },

  /**
   * 生命周期函数--监听页面加载
   */
  onLoad(options) {

  },
  confirmTap(e) {
      console.log(e);
      this.updateSignData(e.detail);
      wx.navigateBack();
  },
  cancelTap(e) {
      wx.navigateBack();
  }
})